import { registerPlugin } from '@wordpress/plugins';
import { useEffect, useState } from '@wordpress/element';
import { PluginDocumentSettingPanel } from '@wordpress/editor';
import { ToggleControl, SelectControl, Notice,  Flex, FlexItem, __experimentalVStack as VStack, ColorPalette } from '@wordpress/components';
import { useEntityProp } from '@wordpress/core-data';
import { useSelect } from '@wordpress/data';
import { __ } from '@wordpress/i18n';
import { PanelColorSettings } from '@wordpress/block-editor';

import './editor.scss';

const BLANK_META_KEY = 'rs_blank_template';
const COLOR_META_KEY = 'rs_page_bg_color';
const TEMPLATE_META_KEY = 'slide_template_v7';

const RevsliderMetaBox = () => {
    const postType = useSelect(select => select( 'core/editor' ).getCurrentPostType(), []);
    const [meta, setMeta] = useEntityProp('postType', postType, 'meta');
    const [modules, setModules] = useState([]);
    const [loading, setLoading] = useState(false);
    const installed = SR7?.E?.revision || '';
    const available = SR7?.E?.latest_revision || '';
    
    const loadModules = () => {
        console.log("loadModules call");
        if (!_tpt || !_tpt.ajax || !_tpt.fixResponse) return requestAnimationFrame(loadModules);
        SR7.E.block_editor = true;
        setLoading(true);
        console.log("loadModules run");
        _tpt.ajax({
            action: 'slider.get.post_templates',
            backend: true,
            data: {module: ['modules']},
            callBack: data => {
                setLoading(false);
                const modules = [];
                const templates = _tpt.fixResponse(data)?.templates || {};
                for (let id in templates) modules.push({label: templates[id], value: id});
                setModules(modules);
            }
        });
    }

    useEffect(() => {
        console.log("useEffect");
        loadModules()
    }, []);

    // Remove module if there is no post type yet or there is no meta like templates
    if (!postType || !meta) {
        return null;
    }

    const options = [
        {label: loading ? __('Loading...', 'revslider') : __('Default', 'revslider'), value: ""},
        ...modules,
    ];

    return (
        <PluginDocumentSettingPanel
            name="slider_revolution_metabox"
            title={ __('Slider Revolution', 'revslider') }
            className="sr--revslider--metabox"
        >
            <ToggleControl
                label={ __("Blank Template", 'revslider') }
                checked={ meta[BLANK_META_KEY] === 'on' }
                onChange={ val => setMeta({...meta, [BLANK_META_KEY]: val ? 'on' : ''}) }
                className="sr--revslider--metabox--blank"
            />
            { meta[BLANK_META_KEY]  === 'on' && (
                <PanelColorSettings
                    title="Colors"
                    colorSettings={[
                        {
                            value: meta[COLOR_META_KEY] || '',
                            onChange: color => setMeta({...meta, [COLOR_META_KEY]: color}),
                            label: __('Background Color', 'revslider')
                        },
                    ]}
                    className="sr--revslider--metabox--color"
                />
            ) }
            <SelectControl
                label={ __('Slide Template', 'revslider') }
                value={ meta[TEMPLATE_META_KEY] || '' }
                options={ options }
                onChange={ val => setMeta({...meta, [TEMPLATE_META_KEY]: val}) }
                className="sr--revslider--metabox--template"
            />
            <Notice status="info" isDismissible={false} className="sr--revslider--metabox--notice">
                <VStack spacing={2}>
                    <Flex justify="space-between"><FlexItem>{ __("Installed Version", 'revslider') }:</FlexItem><FlexItem>{ installed }</FlexItem></Flex>
                    <Flex justify="space-between"><FlexItem>{ __("Available Version", 'revslider') }:</FlexItem><FlexItem>{ available }</FlexItem></Flex>
                </VStack>
            </Notice>
            { !SR7.E.registered && (
                <Notice status="warning" isDismissible={false} className="sr--revslider--metabox--notice">
                    { __('Register Plugin', 'revslider') }
                </Notice>
            ) }
        </PluginDocumentSettingPanel>
    );
};

registerPlugin('revslider-meta-box', {
    render: RevsliderMetaBox,
    icon: 'admin-generic',
});